import React from 'react'
import { useState } from 'react';

const Content = (items,handleChange,) => {
  return (
   <main>
    {(items.length)?(
    <ol>
      {items.map(items => (
        <li key={items.id}>
          <label onDoubleClick={()=>handleChange(items.id)}
                  style={(items.checked) ? {textDecoration:'line-through'}:null}>{items.activity}</label>
          <input type="checkbox" checked={items.checked} onChange={()=>handleChange(items.id)} />
          <button onClick={()=>changeDelete(items.id)}>Delete</button>
        </li>
      ))}
    </ol>
    ):(<p>Your List is Empty</p>)
      }
   </main>
  )
}

export default Content






